ase\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:163:\"https://ja.wordpress.org/support/topic/ultimate_member%e3%81%a7profile_photo%e3%81%8c%e3%82%a2%e3%83%83%e3%83%97%e3%81%a7%e3%81%8d%e3%81%aa%e3%81%84/#post-11686314\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:66:\"返信先: ultimate_memberでprofile_photoがアップできない\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:163:\"https://ja.wordpress.org/support/topic/ultimate_member%e3%81%a7profile_photo%e3%81%8c%e3%82%a2%e3%83%83%e3%83%97%e3%81%a7%e3%81%8d%e3%81%aa%e3%81%84/#post-11686314\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 10 Jan 2024 02:27:36 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:884:\"\n						\n						<p class=\"\"><a href=\"https://ja.wordpress.org/support/users/syntarou/\" class=\"mention\" rel=\"nofollow ugc\">@syntarou</a></p>\n\n\n\n<p class=\"\">そのページのタイトルはちょっとミスリードですね。</p>\n\n\n\n<p class=\"\">記事後半にあるように、</p>\n\n\n\n<p class=\"\"><code>window.onload = </code></p>\n\n\n\n<p class=\"\">ではなく、</p>\n\n\n\n<p class=\"\"><code>window.addEventListener( \'load\',</code></p>\n\n\n\n<p class=\"\">を使えば、onload イベントはいくつでも登録できますね。</p>\n\n\n\n<p class=\"\">どのイベントリスナーでも同様だと思います。</p>\n\n\n\n<p class=\"\">※jQuery の on と Pure JavaScript の addEventListener は全くの同一ではありませんが、同じイベントでも引数（実行される関数など）が異なる場合には複数追加できるとう点では同じです。</p>\n						\n					\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{