 Jan 2024 01:36:11 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:515:\"\n						\n						<p class=\"\">こんにちは</p>\n\n\n\n<p class=\"\"><a href=\"https://ja.wordpress.org/support/topic/%e5%95%8f%e9%a1%8c%e8%a7%a3%e6%b1%ba%e3%81%ae%e3%81%9f%e3%82%81%e3%81%ae%e3%83%81%e3%82%a7%e3%83%83%e3%82%af%e3%83%aa%e3%82%b9%e3%83%88-%e3%83%89%e3%83%a9%e3%83%95%e3%83%88%e7%89%88/\" rel=\"ugc\">問題解決のためのチェックリスト</a>をお試しください。</p>\n\n\n\n<p class=\"\">特に、Autoptimize プラグインを無効にして試してみることをお勧めします。</p>\n						\n					\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:7:\"munyagu\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:4;a:6:{s:4:\"data\";s:55:\"\n					\n					\n					\n					\n					\n\n					\n\n					\n					\n				\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:163:\"https://ja.wordpress.org/support/topic/ultimate_member%e3%81%a7profile_photo%e3%81%8c%e3%82%a2%e3%83%83%e3%83%97%e3%81%a7%e3%81%8d%e3%81%aa%e3%81%84/#post-11686307\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:66:\"返信先: ultimate_memberでprofile_photoがアップできない\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:163:\"https://ja.wordpress.org/support/topic/ultimate_member%e3%81%a7profile_photo%e3%81%8c%e3%82%a2%e3%83%83%e3%83%97%e3%81%a7%e3%81%8d%e3%81%aa%e3%81%84/#post-11686307\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 10 Jan 2024 01:26:23 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1633:\"\n						\n						<p class=\"\">こんにちは</p>\n\n\n\n<p class=\"\">ブラウザのキャッシュの可能性もありますので、ブラウザのキャッシュを削除するか、他のブラウザを使うなどして試してみてください。</p>\n\n\n\n<p class=\"\">また、<a href=\"https://ja.wordpress.org/support/topic/%e5%95%8f%e9%a1%8c%e8%a7%a3%e6%b1%ba%e3%81%ae%e3%81%9f%e3%82%81%e3%81%ae%e3%83%81%e3%82%a7%e3%83%83%e3%82%af%e3%83%aa%e3%82%b9%e3%83%88-%e3%83%89%e3%83%a9%e3%83%95%e3%83%88%e7%89%88/\" rel=\"ugc\">問題解決のためのチェックリスト</a>もお試しください。</p>\n\n\n\n<p class=\"\"><a href=\"https://ja.wordpress.org/support/users/syntarou/\" class=\"mention\" rel=\"nofollow ugc\">@syntarou</a></p>\n\n\n\n<p class=\"\">jQuery の onClick イベントは登録したもの全てが実行されます。</p>\n\n\n\n<p class=\"\">少なくとも、以下のコードでは A B 両方のアラートが表示されます。</p>\n\n\n\n<pre class=\"wp-block-code\"><code>&lt;button&gt;Click Me!&lt;/button&gt;\n&lt;script&gt;\n    $(\'button\').on(\'click\', function(){\n        alert(\'A\');\n    });\n    $(\'button\').on(\'click\', function(){\n        alert(\'B\');\n    });\n&lt;/script&gt;</code></pre>\n\n\n<ul id=\"bbp-reply-revision-log-11686307\" class=\"bbp-reply-revision-log\">\n\n	<li id=\"bbp-reply-revision-log-11686307-item-11686308\" class=\"bbp-reply-revision-log-item\">\n		この返信は2時間、 43分前に<a href=\"https://ja.wordpress.org/support/users/munyagu/\" title=\"munyagu のプロフィールを表示\" class=\"bbp-author-link\"><span  class=\"bbp-author-name\">munyagu</span></a>が編集しました。\n	</li>\n\n</ul>\n\n						\n					\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:7:\"munyagu\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:5;a:6:{s:4:\"data\";s:55:\"\n					\n					\n					\n					\n					\n\n					\n\n					\n					\n				\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:251:\"https://ja.wordpress.org/support/topic/textarea%e3%81%a7%e5%85%a5%e5%8a%9b%e3%81%95%e3%82%8c%e3%81%9f%e3%83%86%e3%82%ad%e3%82%b9%e3%83%88%e3%81%8c%e8%bf%94%e4%bf%a1%e3%83%a1%e3%83%bc%e3%83%ab%e3%81%a7%e6%94%b9%e8%a1%8c%e3%81%95%e3%82%8c/#post-11686305\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:88:\"返信先: textareaで入力されたテキストが返信メールで改行されない\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:251:\"https://ja.wordpress.org/support/topic/textarea%e3%81%a7%e5%85%a5%e5%8a%9b%e3%81%95%e3%82%8c%e3%81%9f%e3%83%86%e3%82%ad%e3%82%b9%e3%83%88%e3%81%8c%e8%bf%94%e4%bf%a1%e3%83%a1%e3%83%bc%e3%83%ab%e3%81%a7%e6%94%b9%e8%a1%8c%e3%81%95%e3%82%8c/#post-11686305\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 10 Jan 2024 01:16:17 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:966:\"\n						\n						<p class=\"\">mhayakawaさん、こんにちは、テーマに、Cocoonは使われていませんか？</p>\n\n\n\n<p class=\"\">Cocoonですと、Cocoon設定の高速化メニューより「HTMLを最小化する」を探して、</p>\n\n\n\n<p class=\"\">これをOFFにする必要があるようですね。</p>\n\n\n\n<p class=\"\">それ以外のテーマでも、これに該当するオプションが原因になっているかもしれないです。試しに設定をはずしてみてはいかがでしょうか。</p>\n\n\n<ul id=\"bbp-reply-revision-log-11686305\" class=\"bbp-reply-revision-log\">\n\n	<li id=\"bbp-reply-revision-log-11686305-item-11686306\" class=\"bbp-reply-revision-log-item\">\n		この返信は2時間、 53分前に<a href=\"https://ja.wordpress.org/support/users/syntarou/\" title=\"syntaro のプロフィールを表示\" class=\"bbp-author-link\"><span  class=\"bbp-author-name\">syntaro</span></a>が編集しました。\n	</li>\n\n</ul>\n\n						\n					\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:7:\"syntaro\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:6;a:6:{s:4:\"data\";s:55:\"\n					\n					\n					\n					\n					\n\n					\n\n					\n					\n				\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:252:\"https://ja.wordpress.org/support/topic/%e8%a7%a3%e6%9e%90%e3%82%84%e3%83%95%e3%82%a9%e3%83%bc%e3%83%a0%e3%81%ae%e9%80%81%e4%bf%a1%e3%83%9c%e3%82%bf%e3%83%b3%e3%81%8c%e6%a9%9f%e8%83%bd%e3%81%97%e3%81%aa%e3%81%8f%e3%81%aa%e3%81%a3%e3%81%9f/#post-11686303\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:163:\"返信先: &lt;abbr title=&quot;成人向けコンテンツ&quot;&gt;[成人向け]&lt;/abbr&gt; 解析やフォームの送信ボタンが機能しなくなった\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:252:\"https://ja.wordpress.org/support/topic/%e8%a7%a3%e6%9e%90%e3%82%84%e3%83%95%e3%82%a9%e3%83%bc%e3%83%a0%e3%81%ae%e9%80%81%e4%bf%a1%e3%83%9c%e3%82%bf%e3%83%b3%e3%81%8c%e6%a9%9f%e8%83%bd%e3%81%97%e3%81%aa%e3%81%8f%e3%81%aa%e3%81%a3%e3%81%9f/#post-11686303\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 10 Jan 2024 01:11:01 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1082:\"\n						\n						<p class=\"\">こんにちは。まず、「プラグインをひとつずつ外して動作確認はしましたが全て問題ありませんでした。」がわかりませんでした。どれを無効にしても動かないものは動かないということではないのですか？前後のうごきません。と問題はありませんでした。がつながりませんでした。すいません。</p>\n\n\n\n<p class=\"\">スタイルシートで、Z-Indexが上位のもので、マウスと近いほうの画面をおおわれていませんか？画面は開いていませんが。なんとなくですが。</p>\n\n\n<ul id=\"bbp-reply-revision-log-11686303\" class=\"bbp-reply-revision-log\">\n\n	<li id=\"bbp-reply-revision-log-11686303-item-11686312\" class=\"bbp-reply-revision-log-item\">\n		この返信は2時間、 10分前に<a href=\"https://ja.wordpress.org/support/users/syntarou/\" title=\"syntaro のプロフィールを表示\" class=\"bbp-author-link\"><span  class=\"bbp-author-name\">syntaro</span></a>が編集しました。\n	</li>\n\n</ul>\n\n						\n					\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:7:\"syntaro\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:7;a:6:{s:4:\"data\";s:55:\"\n					\n					\n					\n					\n					\n\n					\n\n					\n					\n				\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:163:\"https://ja.wordpress.org/support/topic/ultimate_member%e3%81%a7profile_photo%e3%81%8c%e3%82%a2%e3%83%83%e3%83%97%e3%81%a7%e3%81%8d%e3%81%aa%e3%81%84/#post-11686302\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:66:\"返信先: ultimate_memberでprofile_photoがアップできない\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:163:\"https://ja.wordpress.org/support/topic/ultimate_member%e3%81%a7profile_photo%e3%81%8c%e3%82%a2%e3%83%83%e3%83%97%e3%81%a7%e3%81%8d%e3%81%aa%e3%81%84/#post-11686302\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 10 Jan 2024 01:06:59 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1728:\"\n						\n						<p class=\"\">jctaikeuraさん、こんにちは。JavaScriptで何かエラーはなにか表示されていませんか？</p>\n\n\n\n<p class=\"\">というのも、関数名や、OnClickのハンドラーがほかのプラグインとかぶってつぶされている可能性を考えたからです。jQueryのOnClickは、あとから設定したもので上書きされます。それ以外だと、マウスにちかいほうに、透明なレイヤーが追加されてしまって、ボタンまでマウスの信号が届かないとかもありますね。</p>\n\n\n\n<p class=\"\">そのオペレーションは実際にすることはできませんでしたが、ブラウザのデベロッパーツールでなにかエラーがでていないか見ていただければ、なにか解決するかもしれませんね。</p>\n\n\n\n<p class=\"\">プラグインを全部無効にして、ひとつづつ有効にしていき、ぶつかっているものをさがしてultimate-memberのサポートフォーラムに依頼をするという流れだと思います。</p>\n\n\n\n<p class=\"\">その不具合の経験も、プラグインの使用も経験がないので、これ以上は、私にはコメントしにくいですが。</p>\n\n\n\n<p class=\"\"></p>\n\n\n\n<p class=\"\"></p>\n\n\n<ul id=\"bbp-reply-revision-log-11686302\" class=\"bbp-reply-revision-log\">\n\n	<li id=\"bbp-reply-revision-log-11686302-item-11686304\" class=\"bbp-reply-revision-log-item\">\n		この返信は2時間、 58分前に<a href=\"https://ja.wordpress.org/support/users/syntarou/\" title=\"syntaro のプロフィールを表示\" class=\"bbp-author-link\"><span  class=\"bbp-author-name\">syntaro</span></a>が編集しました。\n	</li>\n\n</ul>\n\n						\n					\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:7:\"syntaro\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:55:\"\n					\n					\n					\n					\n					\n\n					\n\n					\n					\n				\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:247:\"https://ja.wordpress.org/support/topic/acf-%e7%ae%a1%e7%90%86%e7%94%bb%e9%9d%a2%e4%b8%8a%e3%81%ae%e6%8a%95%e7%a8%bf%e3%83%95%e3%82%a9%e3%83%bc%e3%83%a0%e3%82%92%e3%82%ab%e3%82%b9%e3%82%bf%e3%83%9e%e3%82%a4%e3%82%ba%e3%81%97%e3%81%9f/#post-11686299\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:70:\"ACF 管理画面上の投稿フォームをカスタマイズしたい\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:247:\"https://ja.wordpress.org/support/topic/acf-%e7%ae%a1%e7%90%86%e7%94%bb%e9%9d%a2%e4%b8%8a%e3%81%ae%e6%8a%95%e7%a8%bf%e3%83%95%e3%82%a9%e3%83%bc%e3%83%a0%e3%82%92%e3%82%ab%e3%82%b9%e3%82%bf%e3%83%9e%e3%82%a4%e3%82%ba%e3%81%97%e3%81%9f/#post-11686299\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 09 Jan 2024 02:32:57 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1035:\"\n						\n						<p class=\"\">こんにちは。</p>\n\n\n\n<p class=\"\">カスタム投稿ページ+ACFを使用して管理画面から開く投稿フォーム自体を</p>\n\n\n\n<p class=\"\">見た目良くデザインしたいのですが、</p>\n\n\n\n<p class=\"\">どのような方法がありますでしょうか。</p>\n\n\n\n<p class=\"\">Elementorというプラグインを使用してフォームのデザインを作成できそうでしたが、投稿ページの場合、カスタム投稿ページのデザインをデフォルトのデザインにする方法がわかりません。</p>\n\n\n<ul id=\"bbp-topic-revision-log-11686299\" class=\"bbp-topic-revision-log\">\n\n	<li id=\"bbp-topic-revision-log-11686299-item-11686300\" class=\"bbp-topic-revision-log-item\">\n		このトピックは<a href=\"https://ja.wordpress.org/support/users/ruri528002/\" title=\"ruri528002 のプロフィールを表示\" class=\"bbp-author-link\"><span  class=\"bbp-author-name\">ruri528002</span></a>が1日、 1時間前に変更しました。\n	</li>\n\n</ul>\n\n						\n					\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:10:\"ruri528002\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:9;a:6:{s:4:\"data\";s:55:\"\n					\n					\n					\n					\n					\n\n					\n\n					\n					\n				\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:163:\"https://ja.wordpress.org/support/topic/ultimate_member%e3%81%a7profile_photo%e3%81%8c%e3%82%a2%e3%83%83%e3%83%97%e3%81%a7%e3%81%8d%e3%81%aa%e3%81%84/#post-11686298\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:55:\"ultimate_memberでprofile_photoがアップできない\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:163:\"https://ja.wordpress.org/support/topic/ultimate_member%e3%81%a7profile_photo%e3%81%8c%e3%82%a2%e3%83%83%e3%83%97%e3%81%a7%e3%81%8d%e3%81%aa%e3%81%84/#post-11686298\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 09 Jan 2024 00:36:34 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1887:\"\n						\n						<p class=\"\">昨年１２月下旬に突然，Ultimate Member でProfile写真とCover写真がアップできなくなりました．１２月１０日頃までは正常にアップ出来ていました．<br />通知を見ると，<br />Date: Thu, 21 Dec 2023 05:42:02 +0000<br />以下のプラグインを更新しました:</p>\n\n\n\n<ul>\n<li>Ultimate Member (バージョン 2.8.0 から2.8.1へ) : <a href=\"https://wordpress.org/plugins/ultimate-member/\" rel=\"nofollow ugc\">https://wordpress.org/plugins/ultimate-member/</a><br /><br />と言うことで，プラグインのアップデートがあったようです．</li>\n</ul>\n\n\n\n<p class=\"\">現象は，ユーザーを新規追加して，Profileを表示して，歯車マークから編集を選び，プロフィル写真，またはCover写真を追加を選び，ファイルを選択して開くと，写真が表示されます．ここでトリミングするまでは動きます．<br />そこで[適用]ボタンを押しても反応しません．<br />すぐに[キャンセル]ボタンを押せば[キャンセル]は機能しますが，写真を入れ替えようとか何かをすると，[キャンセル]ボタンも無反応になります，<br />なお，何もなしの新しくインストールしたワードプレスに ultimatemamber を入れると写真は問題なくアップできますので，何か組み合わせの問題とは思います．</p>\n\n\n\n<p class=\"\">質問１：同様の現象は他の方でも出ていますか？<br />質問２：プラグイン，Ultimate Member を　(バージョン 2.8.1 から2.8.0) に戻す方法はありますか？</p>\n\n\n\n<p class=\"\">なお，添付のリンクはメンバー紹介ページですが，直近参加のメンバーは顔写真が表示できていません．</p>\n\n\n\n<p class=\"\"></p>\n\n\n\n<p class=\"\"></p>\n						\n					\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:10:\"jctaikeura\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}s:27:\"http://www.w3.org/2005/Atom\";a:1:{s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:4:\"href\";s:44:\"https://ja.wordpress.org/support/forums/feed\";s:3:\"rel\";s:4:\"self\";s:4:\"type\";s:19:\"application/rss+xml\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}}}}}}s:4:\"type\";i:128;s:7:\"headers\";O:48:\"WpOrg\\Requests\\Utility\\CaseInsensitiveDictionary\":1:{s:7:\"\0*\0data\";a:10:{s:6:\"server\";s:5:\"nginx\";s:4:\"date\";s:29:\"Wed, 10 Jan 2024 04:11:19 GMT\";s:12:\"content-type\";s:34:\"application/rss+xml; charset=UTF-8\";s:4:\"vary\";s:15:\"Accept-Encoding\";s:6:\"x-olaf\";s:3:\"⛄\";s:12:\"x-robots-tag\";s:15:\"noindex, follow\";s:15:\"x-frame-options\";s:10:\"SAMEORIGIN\";s:16:\"content-encoding\";s:4:\"gzip\";s:7:\"alt-svc\";s:19:\"h3=\":443\"; ma=86400\";s:4:\"x-nc\";s:9:\"HIT ord 2\";}}s:5:\"build\";s:14:\"20211220193300\";}','no');
