INSERT INTO `wp_postmeta` VALUES (3241,191,'point1_naiyou','完全個室なので、トレーニング中の姿をトレーナー以外の人に見られる心配はありません。\r\n知らない人に見られるのが恥ずかしい人も安心してトレーニングできます。\r\n定期カウンセリングもあるので、安心して取り組めます。\r\nライザップが運営するコンビニジム「chocoZAP」も無料で利用できるので、ライザップに行かない日も自分でトレーニングができちゃいます。');
INSERT INTO `wp_postmeta` VALUES (3242,191,'_point1_naiyou','field_6492b97eadbf9');
