INSERT INTO `wp_postmeta` VALUES (3245,191,'point2_naiyou','食事についてもアドバイスをしてくれるだけでなく、電話で栄養の相談ができます。\r\nしかも、電話栄養サポートは入会者無期限でサポートしてくれます。\r\nどんなものを食べればよいのか？どれくらいの量を食べればよいのか？といったことを相談できます。');
