INSERT INTO `wp_postmeta` VALUES (3249,191,'point3_naiyou','トレーニング用のTシャツ・短パンを無料貸出ししてくれます。\r\nまた、バスタオル・フェイスタオルも貸してくれますし、アメニティも置いてあります。\r\nペットボトルのライザップオリジナルウォーターも毎回もらえます。');
