INSERT INTO `wp_postmeta` VALUES (5856,354,'point1_naiyou','しっかり食べて、しっかり痩せる。リバウンドしにくい「痩せる体質」づくりをしています。\r\nBEYONDは糖質制限をするのではなく、糖質を接種するタイミングや種類を最適なものにし、「糖質をコントロール」していきます。\r\n間食も活用して栄養バランスを整えていく食事管理です。');
