INSERT INTO `wp_postmeta` VALUES (5858,354,'point2_title','選びぬかれたトレーナー');
INSERT INTO `wp_postmeta` VALUES (5859,354,'_point2_title','field_64e4651861de6');
INSERT INTO `wp_postmeta` VALUES (5860,354,'point2_naiyou','トレーナー自身がトレーニングをしており、体の美しさを競う大会で、入賞している方がトレーナーに多く在籍しています。\r\nボディメイクを実践しているので、トレーニングを熟知しています。\r\n運動が苦手な方や、トレーニングが初めての方、トレーニングの効果が感じられなかったという方でも、効果的なトレーニング方法を教えてくれます。');
INSERT INTO `wp_postmeta` VALUES (5861,354,'_point2_naiyou','field_64e4651861deb');
