INSERT INTO `wp_postmeta` VALUES (5864,354,'point3_naiyou','トレーニングを続けることがとても大切です。\r\nBEYONDのトレーナーさんは無理な重量や回数を強要することおはありません。あくまで無理なく続けられるトレーニング指導してくれます。\r\n\r\n店舗の内装も居心地がよい清潔感のあるデザインになっているので、明るい気分でトレーニングに集中できる、また来たくなる環境が用意されています。\r\n\r\n一度、見学や無料体験されるとすぐにわかっていただけると思います。');
