INSERT INTO `wp_postmeta` VALUES (7317,433,'point1_title','ストレスフリーな食事管理');
INSERT INTO `wp_postmeta` VALUES (7318,433,'_point1_title','field_64e4651861dd9');
INSERT INTO `wp_postmeta` VALUES (7319,433,'point1_naiyou','しっかり食べて、しっかり痩せる。リバウンドしにくい「痩せる体質」づくりをしています。\r\nBEYONDは糖質制限をするのではなく、糖質を接種するタイミングや種類を最適なものにし、「糖質をコントロール」していきます。\r\n間食も活用して栄養バランスを整えていく食事管理です。');
INSERT INTO `wp_postmeta` VALUES (7320,433,'_point1_naiyou','field_64e4651861dde');
INSERT INTO `wp_postmeta` VALUES (7321,433,'point2_title','選びぬかれたトレーナー');
INSERT INTO `wp_postmeta` VALUES (7322,433,'_point2_title','field_64e4651861de6');
INSERT INTO `wp_postmeta` VALUES (7323,433,'point2_naiyou','トレーナー自身がトレーニングをしており、体の美しさを競う大会で、入賞している方がトレーナーに多く在籍しています。\r\nボディメイクを実践しているので、トレーニングを熟知しています。\r\n運動が苦手な方や、トレーニングが初めての方、トレーニングの効果が感じられなかったという方でも、効果的なトレーニング方法を教えてくれます。');
INSERT INTO `wp_postmeta` VALUES (7324,433,'_point2_naiyou','field_64e4651861deb');
INSERT INTO `wp_postmeta` VALUES (7325,433,'point3_title','モチベーションコントロール');
INSERT INTO `wp_postmeta` VALUES (7326,433,'_point3_title','field_64e4651861def');
INSERT INTO `wp_postmeta` VALUES (7327,433,'point3_naiyou','トレーニングを続けることがとても大切です。\r\nBEYONDのトレーナーさんは無理な重量や回数を強要することおはありません。あくまで無理なく続けられるトレーニング指導してくれます。\r\n\r\n店舗の内装も居心地がよい清潔感のあるデザインになっているので、明るい気分でトレーニングに集中できる、また来たくなる環境が用意されています。\r\n\r\n一度、見学や無料体験されるとすぐにわかっていただけると思います。');
INSERT INTO `wp_postmeta` VALUES (7328,433,'_point3_naiyou','field_64e4651861df4');
