INSERT INTO `wp_posts` VALUES (95,1,'2023-06-08 20:39:18','2023-06-08 11:39:18','<!-- wp:paragraph -->\n<p>社名：株式会社Ｓｉｍｐｌｅ　ｉｓ　Ｂｅｓｔ</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>住所：神奈川県横浜市磯子区田中１−２４−３</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"className\":\"page\",\"fontSize\":\"medium\"} -->\n<ul class=\"page has-medium-font-size\"><!-- wp:list-item {\"className\":\"page\"} -->\n<li class=\"page\">社名：株式会社Ｓｉｍｐｌｅ　ｉｓ　Ｂｅｓｔ</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"className\":\"page\"} -->\n<li class=\"page\">本社所在地：〒２４５−００３５<br>神奈川県横浜市磯子区田中１−２４−３</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>代表取締役：町野 武生</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>設立：２０１９年４月</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>電話番号：045-370-8780</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>事業概要<br>メディア事業<br>リサイクル事業</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->','運営会社','','inherit','closed','closed','','82-revision-v1','','','2023-06-08 20:39:18','2023-06-08 11:39:18','',82,'http://bulkup.local/?p=95',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (96,1,'2023-06-08 20:40:41','2023-06-08 11:40:41','<!-- wp:paragraph -->\n<p>株式会社Simple is Best（以下、当社）は、個人情報保護の重要性を強く認識し、以下の方針に基づき個人情報の保護に努めます。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">1. 定義</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>本プライバシーポリシーにおいて、「個人情報」とは、個人情報保護法にいう、生存する個人に関する情報であって、当該情報に含まれる氏名、住所、電話番号、メールアドレス及びその他の記述等により特定の個人を認識することができるもの（他の情報と容易に照合することができ、それにより特定の個人を識別することができるものを含みます。）をいいます。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">2. 法令等遵守</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、個人情報の取扱いに関する法令、国が定める指針その他の規範を遵守いたします。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">3. 個人情報の収集</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、個人情報の入手を適法かつ公正な手段によっておこないます。 当社は、個人情報を収集する場合、その利用目的を予め通知または公表いたします。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">4. Cookie等の使用について</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、Cookie及びIPアドレス等から施行情報・履歴情報その他の個人のプライバシーに関する情報を収集する場合があります。 利用者は、ブラウザの設定でCookie等を無効にすることにより、当社のCookie等の使用を拒否することができます。 ただし、Cookie等を無効にした場合、サービスの一部または全部を利用できなくなる可能性があります。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">5. 個人情報の利用目的</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、収集した個人情報を以下の目的で利用し、法令により認められる場合を除き、それ以外の目的で個人情報の取り扱いは行いません。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul><!-- wp:list-item {\"className\":\"::marker {   font-size: 50px; }\"} -->\n<li class=\"::marker { font-size: 50px; }\">当社サイト・アプリ・サービス・システムの運営、利便性の向上およびお知らせなどのご案内</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>アフターサービス、苦情対応</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>新サービス、新機能の開発</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>利用者を特定できない形でのマッチング広告の提供</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>マーケティングデータの調査、統計、分析</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>システムの維持、不具合対応</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>本人確認、料金の算出・請求および不正利用防止等</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>その他お問い合わせなどへの対応等</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">6. 情報提供</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、個人情報保護法に基づき、収集した個人情報等を事前に本人の同意を得ることなく、第三者に提供しないものとします。 但し、以下の各号に該当する場合には、この限りではありません。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul><!-- wp:list-item -->\n<li>集計及び分析等により得られたものを、個人を識別又は特定できない態様にて提携先等第三者に開示又は提供する場合。</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>利用目的の達成のために当社が行う業務の全部または一部を第三者に委託する場合。</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>裁判所の発する令状その他裁判所の決定、命令又は法令に基づき開示する場合。</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>当社の権利行使に必要な場合。</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>検察・警察・監督官庁からの適法・適式な情報の照会があった場合。</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>人の生命、身体または財産の保護のために必要がある場合であって、本人の同意を得ることが困難である場合。</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>保険金請求のために保険会社に開示する場合。</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>サービスに関わる部分の事業譲渡、会社分割等の事業承継が行われ、譲渡先に対して法的に権利義務が引き継がれる場合。</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>その他法令により開示が認められている場合。</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">7. リンク先等の個人情報の取り扱いについて</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社運営サイト上やメールマガジンにおいて、外部のサイトへのリンクが貼られることがあります。 この外部のサイトで登録される個人情報は、当社で管轄する情報ではないため、一切の責任を負うことができません。 外部サイトで個人情報を登録される際は、そのサイトのプライバシーポリシーをご確認ください。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">8. 管理体制について</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、「個人情報保護管理規程」を策定し、これに基づき、全ての個人情報に対し、目的外利用、不正アクセス、盗難、紛失、滅失、破壊、改ざん、棄損及び漏えい等を防止するため、必要な予防・是正措置を講じ、適正に管理します。 また、個人情報の処理を第三者に委託する場合は、個人情報保護を規定した契約を締結するとともに、適正な管理が行われるよう管理・監督します。 当社は、個人情報保護のためのマネジメントシステムを継続的に見直し、その改善に努めます。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">9. 正確性の維持</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、利用目的の達成に必要な範囲において、利用者の個人情報等を正確かつ細心の内容に保つよう努めるものとします。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">10. 照会等</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、利用者より、当該利用者の個人情報の照会・訂正・追加・削除・利用の停止または消去を求められた場合、本人確認を実施のうえ、本人による照会等であると確認された場合には、速やかに同照会等に対応します。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">11. 社内教育について</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、個人情報保護ならびに個人情報の漏洩や毀損等を防止する措置として、従業員への教育を実施します。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">12. 改訂について</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>本プライバシーポリシーの内容は予告なく変更される場合があります。 変更が生じた場合はサイト上に掲示することで利用者の皆様へお知らせし、変更後のプライバシーポリシーをサイト上に掲載した時点で変更の効力を生じるものとします。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">個人情報の取扱いに関するお問い合わせ先</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>株式会社Simple is Best 個人情報管理窓口<br>support@simple-is-best.pro</p>\n<!-- /wp:paragraph -->','Privacy Policy','','inherit','closed','closed','','3-revision-v1','','','2023-06-08 20:40:41','2023-06-08 11:40:41','',3,'http://bulkup.local/?p=96',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (97,1,'2023-06-08 20:40:57','2023-06-08 11:40:57','<!-- wp:paragraph -->\n<p>株式会社Simple is Best（以下、当社）は、個人情報保護の重要性を強く認識し、以下の方針に基づき個人情報の保護に努めます。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">1. 定義</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>本プライバシーポリシーにおいて、「個人情報」とは、個人情報保護法にいう、生存する個人に関する情報であって、当該情報に含まれる氏名、住所、電話番号、メールアドレス及びその他の記述等により特定の個人を認識することができるもの（他の情報と容易に照合することができ、それにより特定の個人を識別することができるものを含みます。）をいいます。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">2. 法令等遵守</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、個人情報の取扱いに関する法令、国が定める指針その他の規範を遵守いたします。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">3. 個人情報の収集</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、個人情報の入手を適法かつ公正な手段によっておこないます。 当社は、個人情報を収集する場合、その利用目的を予め通知または公表いたします。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">4. Cookie等の使用について</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、Cookie及びIPアドレス等から施行情報・履歴情報その他の個人のプライバシーに関する情報を収集する場合があります。 利用者は、ブラウザの設定でCookie等を無効にすることにより、当社のCookie等の使用を拒否することができます。 ただし、Cookie等を無効にした場合、サービスの一部または全部を利用できなくなる可能性があります。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">5. 個人情報の利用目的</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、収集した個人情報を以下の目的で利用し、法令により認められる場合を除き、それ以外の目的で個人情報の取り扱いは行いません。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul><!-- wp:list-item {\"className\":\"page-privacy\"} -->\n<li class=\"page-privacy\">当社サイト・アプリ・サービス・システムの運営、利便性の向上およびお知らせなどのご案内</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>アフターサービス、苦情対応</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>新サービス、新機能の開発</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>利用者を特定できない形でのマッチング広告の提供</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>マーケティングデータの調査、統計、分析</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>システムの維持、不具合対応</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>本人確認、料金の算出・請求および不正利用防止等</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>その他お問い合わせなどへの対応等</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">6. 情報提供</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、個人情報保護法に基づき、収集した個人情報等を事前に本人の同意を得ることなく、第三者に提供しないものとします。 但し、以下の各号に該当する場合には、この限りではありません。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul><!-- wp:list-item -->\n<li>集計及び分析等により得られたものを、個人を識別又は特定できない態様にて提携先等第三者に開示又は提供する場合。</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>利用目的の達成のために当社が行う業務の全部または一部を第三者に委託する場合。</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>裁判所の発する令状その他裁判所の決定、命令又は法令に基づき開示する場合。</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>当社の権利行使に必要な場合。</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>検察・警察・監督官庁からの適法・適式な情報の照会があった場合。</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>人の生命、身体または財産の保護のために必要がある場合であって、本人の同意を得ることが困難である場合。</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>保険金請求のために保険会社に開示する場合。</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>サービスに関わる部分の事業譲渡、会社分割等の事業承継が行われ、譲渡先に対して法的に権利義務が引き継がれる場合。</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>その他法令により開示が認められている場合。</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">7. リンク先等の個人情報の取り扱いについて</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社運営サイト上やメールマガジンにおいて、外部のサイトへのリンクが貼られることがあります。 この外部のサイトで登録される個人情報は、当社で管轄する情報ではないため、一切の責任を負うことができません。 外部サイトで個人情報を登録される際は、そのサイトのプライバシーポリシーをご確認ください。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">8. 管理体制について</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、「個人情報保護管理規程」を策定し、これに基づき、全ての個人情報に対し、目的外利用、不正アクセス、盗難、紛失、滅失、破壊、改ざん、棄損及び漏えい等を防止するため、必要な予防・是正措置を講じ、適正に管理します。 また、個人情報の処理を第三者に委託する場合は、個人情報保護を規定した契約を締結するとともに、適正な管理が行われるよう管理・監督します。 当社は、個人情報保護のためのマネジメントシステムを継続的に見直し、その改善に努めます。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">9. 正確性の維持</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、利用目的の達成に必要な範囲において、利用者の個人情報等を正確かつ細心の内容に保つよう努めるものとします。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">10. 照会等</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、利用者より、当該利用者の個人情報の照会・訂正・追加・削除・利用の停止または消去を求められた場合、本人確認を実施のうえ、本人による照会等であると確認された場合には、速やかに同照会等に対応します。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">11. 社内教育について</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、個人情報保護ならびに個人情報の漏洩や毀損等を防止する措置として、従業員への教育を実施します。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">12. 改訂について</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>本プライバシーポリシーの内容は予告なく変更される場合があります。 変更が生じた場合はサイト上に掲示することで利用者の皆様へお知らせし、変更後のプライバシーポリシーをサイト上に掲載した時点で変更の効力を生じるものとします。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">個人情報の取扱いに関するお問い合わせ先</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>株式会社Simple is Best 個人情報管理窓口<br>support@simple-is-best.pro</p>\n<!-- /wp:paragraph -->','Privacy Policy','','inherit','closed','closed','','3-revision-v1','','','2023-06-08 20:40:57','2023-06-08 11:40:57','',3,'http://bulkup.local/?p=97',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (98,1,'2023-06-08 20:41:28','2023-06-08 11:41:28','<!-- wp:paragraph -->\n<p>株式会社Simple is Best（以下、当社）は、個人情報保護の重要性を強く認識し、以下の方針に基づき個人情報の保護に努めます。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">1. 定義</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>本プライバシーポリシーにおいて、「個人情報」とは、個人情報保護法にいう、生存する個人に関する情報であって、当該情報に含まれる氏名、住所、電話番号、メールアドレス及びその他の記述等により特定の個人を認識することができるもの（他の情報と容易に照合することができ、それにより特定の個人を識別することができるものを含みます。）をいいます。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">2. 法令等遵守</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、個人情報の取扱いに関する法令、国が定める指針その他の規範を遵守いたします。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">3. 個人情報の収集</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、個人情報の入手を適法かつ公正な手段によっておこないます。 当社は、個人情報を収集する場合、その利用目的を予め通知または公表いたします。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">4. Cookie等の使用について</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、Cookie及びIPアドレス等から施行情報・履歴情報その他の個人のプライバシーに関する情報を収集する場合があります。 利用者は、ブラウザの設定でCookie等を無効にすることにより、当社のCookie等の使用を拒否することができます。 ただし、Cookie等を無効にした場合、サービスの一部または全部を利用できなくなる可能性があります。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">5. 個人情報の利用目的</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、収集した個人情報を以下の目的で利用し、法令により認められる場合を除き、それ以外の目的で個人情報の取り扱いは行いません。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"className\":\"page-privacy\"} -->\n<ul class=\"page-privacy\"><!-- wp:list-item {\"className\":\"page-privacy\"} -->\n<li class=\"page-privacy\">当社サイト・アプリ・サービス・システムの運営、利便性の向上およびお知らせなどのご案内</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>アフターサービス、苦情対応</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>新サービス、新機能の開発</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>利用者を特定できない形でのマッチング広告の提供</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>マーケティングデータの調査、統計、分析</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>システムの維持、不具合対応</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>本人確認、料金の算出・請求および不正利用防止等</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>その他お問い合わせなどへの対応等</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">6. 情報提供</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、個人情報保護法に基づき、収集した個人情報等を事前に本人の同意を得ることなく、第三者に提供しないものとします。 但し、以下の各号に該当する場合には、この限りではありません。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul><!-- wp:list-item -->\n<li>集計及び分析等により得られたものを、個人を識別又は特定できない態様にて提携先等第三者に開示又は提供する場合。</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>利用目的の達成のために当社が行う業務の全部または一部を第三者に委託する場合。</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>裁判所の発する令状その他裁判所の決定、命令又は法令に基づき開示する場合。</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>当社の権利行使に必要な場合。</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>検察・警察・監督官庁からの適法・適式な情報の照会があった場合。</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>人の生命、身体または財産の保護のために必要がある場合であって、本人の同意を得ることが困難である場合。</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>保険金請求のために保険会社に開示する場合。</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>サービスに関わる部分の事業譲渡、会社分割等の事業承継が行われ、譲渡先に対して法的に権利義務が引き継がれる場合。</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>その他法令により開示が認められている場合。</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">7. リンク先等の個人情報の取り扱いについて</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社運営サイト上やメールマガジンにおいて、外部のサイトへのリンクが貼られることがあります。 この外部のサイトで登録される個人情報は、当社で管轄する情報ではないため、一切の責任を負うことができません。 外部サイトで個人情報を登録される際は、そのサイトのプライバシーポリシーをご確認ください。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">8. 管理体制について</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、「個人情報保護管理規程」を策定し、これに基づき、全ての個人情報に対し、目的外利用、不正アクセス、盗難、紛失、滅失、破壊、改ざん、棄損及び漏えい等を防止するため、必要な予防・是正措置を講じ、適正に管理します。 また、個人情報の処理を第三者に委託する場合は、個人情報保護を規定した契約を締結するとともに、適正な管理が行われるよう管理・監督します。 当社は、個人情報保護のためのマネジメントシステムを継続的に見直し、その改善に努めます。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">9. 正確性の維持</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、利用目的の達成に必要な範囲において、利用者の個人情報等を正確かつ細心の内容に保つよう努めるものとします。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">10. 照会等</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、利用者より、当該利用者の個人情報の照会・訂正・追加・削除・利用の停止または消去を求められた場合、本人確認を実施のうえ、本人による照会等であると確認された場合には、速やかに同照会等に対応します。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">11. 社内教育について</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>当社は、個人情報保護ならびに個人情報の漏洩や毀損等を防止する措置として、従業員への教育を実施します。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">12. 改訂について</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>本プライバシーポリシーの内容は予告なく変更される場合があります。 変更が生じた場合はサイト上に掲示することで利用者の皆様へお知らせし、変更後のプライバシーポリシーをサイト上に掲載した時点で変更の効力を生じるものとします。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"page\"} -->\n<h3 class=\"wp-block-heading page\">個人情報の取扱いに関するお問い合わせ先</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>株式会社Simple is Best 個人情報管理窓口<br>support@simple-is-best.pro</p>\n<!-- /wp:paragraph -->','Privacy Policy','','inherit','closed','closed','','3-revision-v1','','','2023-06-08 20:41:28','2023-06-08 11:41:28','',3,'http://bulkup.local/?p=98',0,'revision','',0);
