INSERT INTO `wp_posts` VALUES (104,1,'2023-06-08 21:20:32','2023-06-08 12:20:32','<table class=\"cform\">\r\n<tbody>\r\n<tr class=\"contact-tr\">\r\n<th>お問い合わせの種類<span class=\"required-srt\">必須</span></th><td>[mwform_select name=\"お問い合わせの種類\" children=\"掲載のご依頼,修正依頼,上記以外のお問い合わせ\"]</td>\r\n</tr>\r\n\r\n<tr class=\"contact-tr\">\r\n<th>企業名または店舗名<span class=\"required-srt\">必須</span></th><td>[mwform_text name=\"企業名または店舗名\" size=\"60\"]</td>\r\n</tr>\r\n\r\n<tr class=\"contact-tr\">\r\n<th>お名前<span class=\"required-srt\">必須</span></th><td>[mwform_text name=\"お名前\" size=\"60\"]</td>\r\n</tr>\r\n\r\n<tr class=\"contact-tr\">\r\n<th>メールアドレス<span class=\"required-srt\">必須</span></th><td>[mwform_email name=\"メールアドレス\" class=\"contact_text\" size=\"60\" placeholder=\"例）simple@bulkup.info\"]</td>\r\n</tr>\r\n\r\n<tr class=\"contact-tr\">\r\n<th>電話番号<span class=\"required-srt\">必須</span></th><td>[mwform_text name=\"電話番号\" size=\"60\" placeholder=\"例）03-0000-0000　ハイフンありでご入力ください\"]</td>\r\n</tr>\r\n\r\n<tr class=\"contact-tr\">\r\n<th>お問い合わせ内容<span class=\"required-srt\">必須</span></th><td>[mwform_textarea name=\"お問い合わせ内容\" cols=\"50\" rows=\"5\" class=\"contact_texteria\" ]</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n\r\n<div class=\"submit-btn\">[mwform_submitButton name=\"確認送信ボタン\" class=\"contact_btn\" confirm_value=\"確認画面へ\" submit_value=\"送信する\"]</div>\r\n\r\n','総合お問い合わせ','','publish','closed','closed','','%e7%b7%8f%e5%90%88%e3%81%8a%e5%95%8f%e3%81%84%e5%90%88%e3%82%8f%e3%81%9b','','','2023-06-09 12:19:47','2023-06-09 03:19:47','',0,'http://bulkup.local/?post_type=mw-wp-form&#038;p=104',0,'mw-wp-form','',0);
