INSERT INTO `wp_posts` VALUES (310,1,'2023-08-22 16:34:48','2023-08-22 07:34:48','a:11:{s:10:\"aria-label\";s:0:\"\";s:4:\"type\";s:8:\"textarea\";s:12:\"instructions\";s:0:\"\";s:8:\"required\";i:0;s:17:\"conditional_logic\";a:1:{i:0;a:1:{i:0;a:2:{s:5:\"field\";s:19:\"field_64e4651861dd4\";s:8:\"operator\";s:7:\"==empty\";}}}s:7:\"wrapper\";a:3:{s:5:\"width\";s:0:\"\";s:5:\"class\";s:0:\"\";s:2:\"id\";s:0:\"\";}s:13:\"default_value\";s:382:\"しっかり食べて、しっかり痩せる。リバウンドしにくい「痩せる体質」づくりをしています。\r\nBEYONDは糖質制限をするのではなく、糖質を接種するタイミングや種類を最適なものにし、「糖質をコントロール」していきます。\r\n間食も活用して栄養バランスを整えていく食事管理です。\";s:9:\"maxlength\";s:0:\"\";s:4:\"rows\";s:0:\"\";s:11:\"placeholder\";s:0:\"\";s:9:\"new_lines\";s:2:\"br\";}','おすすめポイント内容１','point1_naiyou','publish','closed','closed','','field_64e4651861dde','','','2023-08-22 18:15:40','2023-08-22 09:15:40','',296,'http://bulkup.local/?post_type=acf-field&#038;p=310',13,'acf-field','',0);
