INSERT INTO `wp_posts` VALUES (312,1,'2023-08-22 16:34:48','2023-08-22 07:34:48','a:11:{s:10:\"aria-label\";s:0:\"\";s:4:\"type\";s:8:\"textarea\";s:12:\"instructions\";s:0:\"\";s:8:\"required\";i:0;s:17:\"conditional_logic\";a:1:{i:0;a:1:{i:0;a:2:{s:5:\"field\";s:19:\"field_64e4651861dd4\";s:8:\"operator\";s:7:\"==empty\";}}}s:7:\"wrapper\";a:3:{s:5:\"width\";s:0:\"\";s:5:\"class\";s:0:\"\";s:2:\"id\";s:0:\"\";}s:13:\"default_value\";s:469:\"トレーナー自身がトレーニングをしており、体の美しさを競う大会で、入賞している方がトレーナーに多く在籍しています。\r\nボディメイクを実践しているので、トレーニングを熟知しています。\r\n運動が苦手な方や、トレーニングが初めての方、トレーニングの効果が感じられなかったという方でも、効果的なトレーニング方法を教えてくれます。\";s:9:\"maxlength\";s:0:\"\";s:4:\"rows\";s:0:\"\";s:11:\"placeholder\";s:0:\"\";s:9:\"new_lines\";s:0:\"\";}','おすすめポイント内容２','point2_naiyou','publish','closed','closed','','field_64e4651861deb','','','2023-08-22 18:15:40','2023-08-22 09:15:40','',296,'http://bulkup.local/?post_type=acf-field&#038;p=312',15,'acf-field','',0);
