INSERT INTO `wp_posts` VALUES (440,1,'2023-10-04 15:37:44','2023-10-04 06:37:44','<h3 class=\"protein\"><span class=\"midashi midashi_orange\">オススメポイント</span></h3>\r\n<h4>世界売上　No1（※1）</h4>\r\nオプティマムニュートリション（Optimum Nutrition）が製造販売する「ゴールドスタンダード100％ホエイ」は、世界中で愛飲されている定番プロテインです。\r\nオプティマムニュートリションとは、１９８６年にアメリカで創業したスポーツ栄養製品ブランドです。\r\n世界９０ヶ国以上で販売され、プロテインだけではなく、あらゆるサプリメントを製造販売しています。\r\n\r\n<h4>安心安全な品質</h4>\r\nイギリスのミドラスブラ（Middlesbrough）に製造施設をもっており、自社管理することで安心安全な商品の製造を行っています。\r\n原材料には分析証明書が必要とされ、適合性の検査と再検査が行い、常に最高品質を維持しています。\r\n製造された商品の品質管理は、GMP(Good Manufacturing Practice　製造業者および製造販売業者に求められる適正製造規範）登録されている管理基準に準拠した施設で毎日検査され徹底されています。\r\n\r\n<h3 class=\"protein\"><span class=\"midashi midashi_blue\">特徴</span></h3>\r\n<ul class=\"protein\">\r\n	<li>ホエイタンパク質分離物が主成分</li>\r\n	<li>炭水化物と脂質分をできるだけ除去</li>\r\n	<li>BCAAやEAA（天然必須アミノ酸）も含有</li>\r\n	<li>グルテンフリー</li></ul>\r\n<h3 class=\"protein\"><span class=\"midashi midashi_lightblue\">飲み方</span></h3>\r\n<div><a href=\"https://t.afi-b.com/visit.php?a=p12918M-r429731g&p=2906771e\" rel=\"nofollow\">\r\n<picture>\r\n<source media=\"(max-width:768px)\" srcset=\"https://www.afi-b.com/upload_image/12918-1626788607-3.jpg\" width=\"936\" height=\"120\" style=\"border:none;\" alt=\"LYFT\">\r\n<source media=\"(min-width:769px)\" srcset=\"https://www.afi-b.com/upload_image/12918-1631646607-3.jpg\" width=\"600\" height=\"500\" style=\"border:none;\" alt=\"LYFT\"><img src=\"https://www.afi-b.com/upload_image/12918-1631646607-3.jpg\" width=\"936\" height=\"120\" style=\"border:none;\" alt=\"LYFT\" /></picture>\r\n</a><img src=\"https://t.afi-b.com/lead/p12918M/2906771e/r429731g\" width=\"1\" height=\"1\" style=\"border:none;\" /></div>\r\n[tpphp file=\'tp-goldstandard\']\r\n[tpphp file=\'tp-lyft\']','テストマッスルプロテイン','オプティマムニュートリション（Optimum Nutrition）が製造販売する「ゴールドスタンダード100％ホエイ」は、世界中で愛飲されている定番プロテインです。\r\nオプティマムニュートリションとは、１９８６年にアメリカで創業したスポーツ栄養製品ブランドです。\r\n世界９０ヶ国以上で販売され、プロテインだけではなく、あらゆるサプリメントを製造販売しています。','publish','closed','open','','%e3%83%86%e3%82%b9%e3%83%88%e3%83%97%e3%83%ad%e3%83%86%e3%82%a4%e3%83%b3','','','2023-12-14 08:48:17','2023-12-13 23:48:17','',0,'http://bulkup.local/?post_type=protein_info&#038;p=440',0,'protein_info','',0);
