INSERT INTO `wp_posts` VALUES (497,1,'2023-11-08 07:43:03','2023-11-07 22:43:03','<h3 class=\"protein\"><span class=\"midashi midashi_orange\">オススメポイント</span></h3>\r\n<h4>世界売上　No1（※1）</h4>\r\nオプティマムニュートリション（Optimum Nutrition）が製造販売する「ゴールドスタンダード100％ホエイ」は、世界中で愛飲されている定番プロテインです。\r\nオプティマムニュートリションとは、１９８６年にアメリカで創業したスポーツ栄養製品ブランドです。\r\n世界９０ヶ国以上で販売され、プロテインだけではなく、あらゆるサプリメントを製造販売しています。\r\n\r\n<h4>安心安全な品質</h4>\r\nイギリスのミドラスブラ（Middlesbrough）に製造施設をもっており、自社管理することで安心安全な商品の製造を行っています。\r\n原材料には分析証明書が必要とされ、適合性の検査と再検査が行い、常に最高品質を維持しています。\r\n製造された商品の品質管理は、GMP(Good Manufacturing Practice　製造業者および製造販売業者に求められる適正製造規範）登録されている管理基準に準拠した施設で毎日検査され徹底されています。','テストプロテイン','','inherit','closed','closed','','440-revision-v1','','','2023-11-08 07:43:03','2023-11-07 22:43:03','',440,'http://bulkup.local/?p=497',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (499,1,'2023-11-08 07:47:52','2023-11-07 22:47:52','<h3 class=\"protein\"><span class=\"midashi midashi_orange\">オススメポイント</span></h3>\r\n<h4>世界売上　No1（※1）</h4>\r\nオプティマムニュートリション（Optimum Nutrition）が製造販売する「ゴールドスタンダード100％ホエイ」は、世界中で愛飲されている定番プロテインです。\r\nオプティマムニュートリションとは、１９８６年にアメリカで創業したスポーツ栄養製品ブランドです。\r\n世界９０ヶ国以上で販売され、プロテインだけではなく、あらゆるサプリメントを製造販売しています。\r\n\r\n<h4>安心安全な品質</h4>\r\nイギリスのミドラスブラ（Middlesbrough）に製造施設をもっており、自社管理することで安心安全な商品の製造を行っています。\r\n原材料には分析証明書が必要とされ、適合性の検査と再検査が行い、常に最高品質を維持しています。\r\n製造された商品の品質管理は、GMP(Good Manufacturing Practice　製造業者および製造販売業者に求められる適正製造規範）登録されている管理基準に準拠した施設で毎日検査され徹底されています。\r\n\r\n<h3 class=\"protein\"><span>特徴</span></h3>\r\n<ul>\r\n	<li>ホエイタンパク質分離物我主成分</li>\r\n	<li>炭水化物と脂質分をできるだけ除去</li>\r\n	<li>BCAAやEAA（天然必須アミノ酸）も含有</li>\r\n	<li>グルテンフリー</li></ul>\r\n','テストプロテイン','','inherit','closed','closed','','440-revision-v1','','','2023-11-08 07:47:52','2023-11-07 22:47:52','',440,'http://bulkup.local/?p=499',0,'revision','',0);
